import asyncio
import json
import uuid
from dataclasses import dataclass, field
from typing import Dict, Optional, Set, Any

import websockets
from websockets.server import WebSocketServerProtocol


@dataclass
class Item:
    item_id: str
    name: str
    owner_id: str


@dataclass
class Player:
    player_id: str
    name: str
    websocket: Optional[WebSocketServerProtocol] = None
    inventory: Set[str] = field(default_factory=set)


class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[str, Item] = {}
        self._lock = asyncio.Lock()

    async def register(self, websocket: WebSocketServerProtocol, payload: Dict[str, Any]) -> str:
        player_id = payload.get("player_id") or str(uuid.uuid4())
        name = payload.get("name", f"Player_{player_id[:8]}")
        async with self._lock:
            player = self.players.get(player_id)
            if player is None:
                player = Player(player_id=player_id, name=name, websocket=websocket)
                self.players[player_id] = player
            else:
                player.name = name
                player.websocket = websocket
        await self._send(websocket, {"type": "registered", "player_id": player_id, "name": name})
        return player_id

    async def unregister(self, websocket: WebSocketServerProtocol):
        async with self._lock:
            for player in self.players.values():
                if player.websocket == websocket:
                    player.websocket = None
                    break

    async def create_item(self, owner_id: str, name: str) -> Item:
        async with self._lock:
            if owner_id not in self.players:
                raise ValueError("owner_not_found")
            item_id = str(uuid.uuid4())
            item = Item(item_id=item_id, name=name, owner_id=owner_id)
            self.items[item_id] = item
            self.players[owner_id].inventory.add(item_id)
            return item

    async def transfer_item(self, from_player_id: str, to_player_id: str, item_id: str) -> Dict[str, Any]:
        async with self._lock:
            if from_player_id not in self.players:
                return {"ok": False, "error": "from_player_not_found"}
            if to_player_id not in self.players:
                return {"ok": False, "error": "to_player_not_found"}
            item = self.items.get(item_id)
            if item is None:
                return {"ok": False, "error": "item_not_found"}
            if item.owner_id != from_player_id:
                return {"ok": False, "error": "not_item_owner"}

            self.players[from_player_id].inventory.discard(item_id)
            self.players[to_player_id].inventory.add(item_id)
            item.owner_id = to_player_id

            await self._notify_player(from_player_id, {
                "type": "inventory_update",
                "action": "item_transferred_out",
                "item_id": item_id,
                "to_player_id": to_player_id,
            })
            await self._notify_player(to_player_id, {
                "type": "inventory_update",
                "action": "item_transferred_in",
                "item_id": item_id,
                "from_player_id": from_player_id,
            })
            return {"ok": True, "item_id": item_id, "new_owner_id": to_player_id}

    async def handle_message(self, websocket: WebSocketServerProtocol, raw_message: str):
        try:
            message = json.loads(raw_message)
        except json.JSONDecodeError:
            await self._send(websocket, {"type": "error", "error": "invalid_json"})
            return

        action = message.get("action")
        if action == "register":
            await self.register(websocket, message)
            return

        player_id = message.get("player_id")
        if not player_id:
            await self._send(websocket, {"type": "error", "error": "player_id_required"})
            return

        if action == "create_item":
            name = message.get("name", "Unknown Item")
            try:
                item = await self.create_item(player_id, name)
                await self._send(websocket, {
                    "type": "item_created",
                    "item": {"item_id": item.item_id, "name": item.name, "owner_id": item.owner_id},
                })
            except ValueError as e:
                await self._send(websocket, {"type": "error", "error": str(e)})
            return

        if action == "transfer_item":
            to_player_id = message.get("to_player_id")
            item_id = message.get("item_id")
            if not to_player_id or not item_id:
                await self._send(websocket, {"type": "error", "error": "to_player_id_and_item_id_required"})
                return
            result = await self.transfer_item(player_id, to_player_id, item_id)
            await self._send(websocket, {"type": "transfer_result", **result})
            return

        if action == "inventory":
            await self._send(websocket, {"type": "inventory", "items": await self.get_inventory(player_id)})
            return

        await self._send(websocket, {"type": "error", "error": "unknown_action"})

    async def get_inventory(self, player_id: str):
        async with self._lock:
            player = self.players.get(player_id)
            if not player:
                return []
            return [
                {"item_id": item_id, "name": self.items[item_id].name, "owner_id": self.items[item_id].owner_id}
                for item_id in player.inventory
                if item_id in self.items
            ]

    async def _notify_player(self, player_id: str, payload: Dict[str, Any]):
        player = self.players.get(player_id)
        if not player or not player.websocket:
            return
        try:
            await self._send(player.websocket, payload)
        except Exception:
            pass

    async def _send(self, websocket: WebSocketServerProtocol, payload: Dict[str, Any]):
        await websocket.send(json.dumps(payload))


server = GameServer()


async def connection_handler(websocket: WebSocketServerProtocol):
    try:
        async for message in websocket:
            await server.handle_message(websocket, message)
    finally:
        await server.unregister(websocket)


async def main(host: str = "0.0.0.0", port: int = 8765):
    async with websockets.serve(connection_handler, host, port):
        await asyncio.Future()


if __name__ == "__main__":
    asyncio.run(main())